<svg viewBox="0 0 700 260" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="26" fill="#fafafa" font-size="13" font-weight="700" font-family="sans-serif">Bitcoin Esta Semana — +8-9% Desde el Mínimo</text>
  <text x="20" y="42" fill="#71717a" font-size="10" font-family="sans-serif">29 jun (lun)-5 jul (dom) · Tendencia aproximada, no cierres diarios exactos</text>
